   1→import React, { useState, useEffect, useCallback } from 'react';
   2→import { User, AnalysisResult } from '../types';
   3→import {
   4→  AuthorProfile, OrganizationProfile, TrustSignalsConfig, EEAT_CREDITS,
   5→  GeneratedAuthorBio, GeneratedAboutPage, GeneratedTrustBlock,
   6→  GeneratedCredentials, GeneratedCitationBlock, EeatAuditResult,
   7→  Credential, Education, Certification, Award, Publication, SocialProfile,
   8→  ReviewAggregate, MediaMention,
   9→} from '../types/eeat';
  10→import {
  11→  generateAuthorBio, generateAboutPage, generateTrustSignals,
  12→  generateCredentials, generateCitationBlock, auditEeat,
  13→  saveAuditToHistory, getAuditHistory, compareAudits,
  14→} from '../services/eeat';
  15→import type { EeatAuditHistoryEntry, AuditComparison } from '../services/eeat';
  16→import {
  17→  ArrowLeft, Sparkles, Loader2, Copy, Check, UserCircle, Building2,
  18→  Shield, Award as AwardIcon, FileText, BarChart3, Plus, X, Search,
  19→  ChevronDown, ChevronUp, Zap, CheckCircle, AlertTriangle, XCircle,
  20→  Download, History, ArrowRight, TrendingUp, Wrench, Clock, Trash2,
  21→} from 'lucide-react';
  22→import {
  23→  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  24→  ResponsiveContainer,
  25→} from 'recharts';
  26→import PageHeader from '../components/layout/PageHeader';
  27→
  28→interface Props {
  29→  onBack: () => void;
  30→  user: User | null;
  31→  onDeductCredits: (amount: number) => boolean;
  32→  history?: AnalysisResult[];
  33→}
  34→
  35→// ── Tabs config ──
  36→const TABS = [
  37→  { id: 'author-bio', label: 'Bio Auteur', icon: UserCircle, color: 'text-emerald-400', cost: EEAT_CREDITS.authorBio },
  38→  { id: 'about-page', label: 'Page A Propos', icon: Building2, color: 'text-blue-400', cost: EEAT_CREDITS.aboutPage },
  39→  { id: 'trust-signals', label: 'Trust Signals', icon: Shield, color: 'text-amber-400', cost: EEAT_CREDITS.trustSignals },
  40→  { id: 'credentials', label: 'Credentials', icon: AwardIcon, color: 'text-purple-400', cost: EEAT_CREDITS.credentials },
  41→  { id: 'citation-block', label: 'Bloc Citation', icon: FileText, color: 'text-cyan-400', cost: EEAT_CREDITS.citationBlock },
  42→  { id: 'eeat-audit', label: 'Audit E-E-A-T', icon: BarChart3, color: 'text-rose-400', cost: EEAT_CREDITS.audit },
  43→  { id: 'historique', label: 'Historique', icon: History, color: 'text-indigo-400', cost: 0 },
  44→] as const;
  45→
  46→type TabId = typeof TABS[number]['id'];
  47→
  48→// ── Reusable small components ──
  49→const InputField: React.FC<{ label: string; value: string; onChange: (v: string) => void; placeholder?: string; required?: boolean; type?: string }> = ({ label, value, onChange, placeholder, required, type = 'text' }) => (
  50→  <div>
  51→    <label className="block text-sm font-medium text-gray-300 mb-1.5">{label} {required && <span className="text-red-400">*</span>}</label>
  52→    <input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
  53→      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
  54→  </div>
  55→);
  56→
  57→const TextArea: React.FC<{ label: string; value: string; onChange: (v: string) => void; placeholder?: string; rows?: number }> = ({ label, value, onChange, placeholder, rows = 3 }) => (
  58→  <div>
  59→    <label className="block text-sm font-medium text-gray-300 mb-1.5">{label}</label>
  60→    <textarea value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} rows={rows}
  61→      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors resize-none" />
  62→  </div>
  63→);
  64→
  65→const CodeBlock: React.FC<{ code: string; title: string }> = ({ code, title }) => {
  66→  const [copied, setCopied] = useState(false);
  67→  const handleCopy = () => { navigator.clipboard.writeText(code); setCopied(true); setTimeout(() => setCopied(false), 2000); };
  68→  return (
  69→    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
  70→      <div className="flex items-center justify-between px-4 py-2 border-b border-[var(--border-subtle)]">
  71→        <span className="text-xs text-gray-500 font-semibold">{title}</span>
  72→        <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-purple-400 transition-colors">
  73→          {copied ? <Check size={12} /> : <Copy size={12} />} {copied ? 'Copie' : 'Copier'}
  74→        </button>
  75→      </div>
  76→      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-80 custom-scrollbar"><code>{code}</code></pre>
  77→    </div>
  78→  );
  79→};
  80→
  81→const ScoreRing: React.FC<{ score: number; size?: number; label?: string }> = ({ score, size = 100, label }) => {
  82→  const radius = (size - 10) / 2;
  83→  const circumference = 2 * Math.PI * radius;
  84→  const offset = circumference - (score / 100) * circumference;
  85→  const color = score >= 70 ? '#22c55e' : score >= 40 ? '#f59e0b' : '#ef4444';
  86→  return (
  87→    <div className="flex flex-col items-center gap-2">
  88→      <div className="relative" style={{ width: size, height: size }}>
  89→        <svg width={size} height={size} className="transform -rotate-90">
  90→          <circle cx={size / 2} cy={size / 2} r={radius} stroke="rgba(255,255,255,0.05)" strokeWidth="6" fill="none" />
  91→          <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="6" fill="none"
  92→            strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
  93→            style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
  94→        </svg>
  95→        <div className="absolute inset-0 flex flex-col items-center justify-center">
  96→          <span className="text-2xl font-bold text-white">{score}</span>
  97→          <span className="text-[9px] text-gray-500 uppercase">/100</span>
  98→        </div>
  99→      </div>
 100→      {label && <span className="text-xs text-gray-400 font-medium">{label}</span>}
 101→    </div>
 102→  );
 103→};
 104→
 105→const ScoreBar: React.FC<{ label: string; score: number; color: string }> = ({ label, score, color }) => (
 106→  <div className="space-y-1.5">
 107→    <div className="flex justify-between text-xs">
 108→      <span className="text-gray-400">{label}</span>
 109→      <span className="text-gray-300 font-bold">{score}/100</span>
 110→    </div>
 111→    <div className="w-full h-2 bg-white/[0.03] rounded-full overflow-hidden">
 112→      <div className="h-full rounded-full transition-all duration-700" style={{ width: `${score}%`, background: color }} />
 113→    </div>
 114→  </div>
 115→);
 116→
 117→// ── Feature 7: ExportPanel Component ──
 118→type ExportFormat = 'html-raw' | 'wordpress' | 'webflow';
 119→
 120→const wrapForFormat = (code: string, format: ExportFormat): string => {
 121→  if (format === 'html-raw') return code;
 122→  if (format === 'wordpress') {
 123→    return `<!-- WordPress Shortcode Block -->
 124→[citedby_eeat_block]
 125→<div class="citedby-eeat-wrapper">
 126→${code}
 127→</div>
 128→[/citedby_eeat_block]
 129→
 130→<!-- Alternative: Use as Custom HTML Block in Gutenberg -->
 131→<!-- wp:html -->
 132→<div class="citedby-eeat-wrapper">
 133→${code}
 134→</div>
 135→<!-- /wp:html -->`;
 136→  }
 137→  // webflow
 138→  return `<!-- Webflow Embed Block -->
 139→<div class="w-embed citedby-eeat-embed" data-citedby="true" data-eeat-component="true" data-source="citedby-ai">
 140→  <style>
 141→    .citedby-eeat-embed { font-family: inherit; }
 142→    .citedby-eeat-embed * { box-sizing: border-box; }
 143→  </style>
 144→${code}
 145→</div>`;
 146→};
 147→
 148→const ExportPanel: React.FC<{ code: string; title: string }> = ({ code, title }) => {
 149→  const [format, setFormat] = useState<ExportFormat>('html-raw');
 150→  const [copied, setCopied] = useState(false);
 151→
 152→  const formattedCode = wrapForFormat(code, format);
 153→
 154→  const handleCopy = () => {
 155→    navigator.clipboard.writeText(formattedCode);
 156→    setCopied(true);
 157→    setTimeout(() => setCopied(false), 2000);
 158→  };
 159→
 160→  const handleDownload = () => {
 161→    const blob = new Blob([formattedCode], { type: 'text/html' });
 162→    const url = URL.createObjectURL(blob);
 163→    const a = document.createElement('a');
 164→    a.href = url;
 165→    a.download = `${title.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}.html`;
 166→    document.body.appendChild(a);
 167→    a.click();
 168→    document.body.removeChild(a);
 169→    URL.revokeObjectURL(url);
 170→  };
 171→
 172→  const formatOptions: { id: ExportFormat; label: string }[] = [
 173→    { id: 'html-raw', label: 'HTML brut' },
 174→    { id: 'wordpress', label: 'WordPress Shortcode' },
 175→    { id: 'webflow', label: 'Webflow Embed' },
 176→  ];
 177→
 178→  return (
 179→    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
 180→      <div className="px-4 py-3 border-b border-[var(--border-subtle)] space-y-3">
 181→        <div className="flex items-center justify-between">
 182→          <span className="text-xs text-gray-500 font-semibold">{title} - Export CMS</span>
 183→        </div>
 184→        {/* Format selector */}
 185→        <div className="flex gap-1.5">
 186→          {formatOptions.map(opt => (
 187→            <button key={opt.id} onClick={() => setFormat(opt.id)}
 188→              className={`px-3 py-1.5 text-[11px] font-medium rounded-lg transition-all ${
 189→                format === opt.id
 190→                  ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30'
 191→                  : 'bg-white/[0.03] text-gray-500 border border-[var(--border-subtle)] hover:text-gray-300'
 192→              }`}>
 193→              {opt.label}
 194→            </button>
 195→          ))}
 196→        </div>
 197→        {/* Action buttons */}
 198→        <div className="flex gap-2">
 199→          <button onClick={handleCopy}
 200→            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-purple-500/10 text-purple-400 border border-purple-500/20 hover:bg-purple-500/20 transition-all">
 201→            {copied ? <Check size={12} /> : <Copy size={12} />}
 202→            {copied ? 'Copie !' : 'Copier HTML'}
 203→          </button>
 204→          <button onClick={handleDownload}
 205→            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-white/[0.03] text-gray-400 border border-white/[0.06] hover:text-gray-200 transition-all">
 206→            <Download size={12} />
 207→            Telecharger .html
 208→          </button>
 209→        </div>
 210→      </div>
 211→      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-60 custom-scrollbar"><code>{formattedCode}</code></pre>
 212→    </div>
 213→  );
 214→};
 215→
 216→// ── Feature 8: Workflow mapping ──
 217→const CATEGORY_TO_TAB: Record<string, TabId> = {
 218→  experience: 'citation-block',
 219→  expertise: 'author-bio',
 220→  authority: 'trust-signals',
 221→  trust: 'about-page',
 222→};
 223→
 224→const CATEGORY_TAB_LABELS: Record<string, string> = {
 225→  experience: 'Bloc Citation',
 226→  expertise: 'Bio Auteur',
 227→  authority: 'Trust Signals',
 228→  trust: 'Page A Propos',
 229→};
 230→
 231→// ═══════════════════════════════════════════
 232→// MAIN COMPONENT
 233→// ═══════════════════════════════════════════
 234→
 235→const EeatBuilder: React.FC<Props> = ({ onBack, user, onDeductCredits, history: appHistory }) => {
 236→  const [activeTab, setActiveTab] = useState<TabId>('author-bio');
 237→  const [isLoading, setIsLoading] = useState(false);
 238→
 239→  // ── Author Bio state ──
 240→  const [authorName, setAuthorName] = useState('');
 241→  const [authorTitle, setAuthorTitle] = useState('');
 242→  const [authorOrg, setAuthorOrg] = useState('');
 243→  const [authorYears, setAuthorYears] = useState('');
 244→  const [authorSpecs, setAuthorSpecs] = useState('');
 245→  const [authorLinkedin, setAuthorLinkedin] = useState('');
 246→  const [authorPhotoUrl, setAuthorPhotoUrl] = useState('');
 247→  const [authorEducation, setAuthorEducation] = useState<Education[]>([]);
 248→  const [authorCredentials, setAuthorCredentials] = useState<Credential[]>([]);
 249→  const [bioResult, setBioResult] = useState<GeneratedAuthorBio | null>(null);
 250→
 251→  // ── About Page state ──
 252→  const [orgName, setOrgName] = useState('');
 253→  const [orgType, setOrgType] = useState<'Organization' | 'LocalBusiness' | 'Corporation'>('Organization');
 254→  const [orgFounding, setOrgFounding] = useState('');
 255→  const [orgIndustry, setOrgIndustry] = useState('');
 256→  const [orgSpecs, setOrgSpecs] = useState('');
 257→  const [orgServices, setOrgServices] = useState('');
 258→  const [orgEmail, setOrgEmail] = useState('');
 259→  const [orgSiteUrl, setOrgSiteUrl] = useState('');
 260→  const [orgCity, setOrgCity] = useState('');
 261→  const [orgCountry, setOrgCountry] = useState('France');
 262→  const [aboutResult, setAboutResult] = useState<GeneratedAboutPage | null>(null);
 263→
 264→  // ── Trust Signals state ──
 265→  const [trustOrgName, setTrustOrgName] = useState('');
 266→  const [trustCerts, setTrustCerts] = useState('');
 267→  const [trustPress, setTrustPress] = useState('');
 268→  const [trustGuarantees, setTrustGuarantees] = useState('');
 269→  const [trustProof, setTrustProof] = useState('');
 270→  const [trustReviewPlatform, setTrustReviewPlatform] = useState('google');
 271→  const [trustReviewRating, setTrustReviewRating] = useState('4.5');
 272→  const [trustReviewCount, setTrustReviewCount] = useState('150');
 273→  const [trustResult, setTrustResult] = useState<GeneratedTrustBlock | null>(null);
 274→
 275→  // ── Credentials state ──
 276→  const [credName, setCredName] = useState('');
 277→  const [credTitle, setCredTitle] = useState('');
 278→  const [credOrg, setCredOrg] = useState('');
 279→  const [credYears, setCredYears] = useState('');
 280→  const [credSpecs, setCredSpecs] = useState('');
 281→  const [credEducation, setCredEducation] = useState<Education[]>([]);
 282→  const [credCredentials, setCredCredentials] = useState<Credential[]>([]);
 283→  const [credAwards, setCredAwards] = useState<Award[]>([]);
 284→  const [credResult, setCredResult] = useState<GeneratedCredentials | null>(null);
 285→
 286→  // ── Citation Block state ──
 287→  const [citeName, setCiteName] = useState('');
 288→  const [citeTitle, setCiteTitle] = useState('');
 289→  const [citeOrg, setCiteOrg] = useState('');
 290→  const [citeYears, setCiteYears] = useState('');
 291→  const [citeSpecs, setCiteSpecs] = useState('');
 292→  const [citeLinkedin, setCiteLinkedin] = useState('');
 293→  const [citePhotoUrl, setCitePhotoUrl] = useState('');
 294→  const [citeArticleTitle, setCiteArticleTitle] = useState('');
 295→  const [citeResult, setCiteResult] = useState<GeneratedCitationBlock | null>(null);
 296→
 297→  // ── Audit state ──
 298→  const [auditUrl, setAuditUrl] = useState('');
 299→  const [auditBrand, setAuditBrand] = useState('');
 300→  const [auditResult, setAuditResult] = useState<EeatAuditResult | null>(null);
 301→
 302→  // ── Feature 9: History state ──
 303→  const [auditHistory, setAuditHistory] = useState<EeatAuditHistoryEntry[]>([]);
 304→  const [selectedComparison, setSelectedComparison] = useState<AuditComparison | null>(null);
 305→
 306→  // Load history on mount
 307→  useEffect(() => {
 308→    setAuditHistory(getAuditHistory());
 309→  }, []);
 310→
 311→  // ── Build AuthorProfile helper ──
 312→  const buildAuthorProfile = (name: string, title: string, org: string, years: string, specs: string, linkedin: string, photoUrl: string, education: Education[], credentials: Credential[], awards?: Award[], publications?: Publication[]): AuthorProfile => ({
 313→    name, jobTitle: title, organization: org,
 314→    yearsExperience: parseInt(years) || 5,
 315→    specializations: specs.split(',').map(s => s.trim()).filter(Boolean),
 316→    credentials,
 317→    certifications: [],
 318→    education,
 319→    awards: awards || [],
 320→    publications: publications || [],
 321→    socialProfiles: linkedin ? [{ platform: 'linkedin' as const, url: linkedin }] : [],
 322→    photoUrl: photoUrl || undefined,
 323→  });
 324→
 325→  // ── Handlers ──
 326→  const handleGenerateBio = async () => {
 327→    if (!authorName || !authorTitle) return;
 328→    if (!onDeductCredits(EEAT_CREDITS.authorBio)) return;
 329→    setIsLoading(true); setBioResult(null);
 330→    try {
 331→      const profile = buildAuthorProfile(authorName, authorTitle, authorOrg, authorYears, authorSpecs, authorLinkedin, authorPhotoUrl, authorEducation, authorCredentials);
 332→      const result = await generateAuthorBio(profile);
 333→      setBioResult(result);
 334→    } catch (e) { console.error(e); }
 335→    finally { setIsLoading(false); }
 336→  };
 337→
 338→  const handleGenerateAbout = async () => {
 339→    if (!orgName || !orgEmail) return;
 340→    if (!onDeductCredits(EEAT_CREDITS.aboutPage)) return;
 341→    setIsLoading(true); setAboutResult(null);
 342→    try {
 343→      const org: OrganizationProfile = {
 344→        name: orgName, type: orgType, foundingDate: orgFounding || '2020-01-01',
 345→        industry: orgIndustry, specializations: orgSpecs.split(',').map(s => s.trim()).filter(Boolean),
 346→        servicesOffered: orgServices.split(',').map(s => s.trim()).filter(Boolean),
 347→        certifications: [], awards: [], partnerships: [], mediaAppearances: [],
 348→        reviews: [], guarantees: [], accreditations: [],
 349→        address: { street: '', city: orgCity, postalCode: '', country: orgCountry },
 350→        email: orgEmail, socialProfiles: [], siteUrl: orgSiteUrl,
 351→      };
 352→      const result = await generateAboutPage(org);
 353→      setAboutResult(result);
 354→    } catch (e) { console.error(e); }
 355→    finally { setIsLoading(false); }
 356→  };
 357→
 358→  const handleGenerateTrust = async () => {
 359→    if (!trustOrgName) return;
 360→    if (!onDeductCredits(EEAT_CREDITS.trustSignals)) return;
 361→    setIsLoading(true); setTrustResult(null);
 362→    try {
 363→      const config: TrustSignalsConfig = {
 364→        certifications: trustCerts.split('\n').filter(Boolean).map(c => {
 365→          const parts = c.split('|').map(s => s.trim());
 366→          return { name: parts[0] || c, issuer: parts[1] || '' };
 367→        }),
 368→        securityBadges: [{ type: 'ssl' }, { type: 'gdpr' }, { type: 'secure_payment' }],
 369→        guarantees: trustGuarantees.split('\n').filter(Boolean).map(g => ({
 370→          type: 'satisfaction' as const, details: g,
 371→        })),
 372→        socialProof: trustProof.split('\n').filter(Boolean).map(s => ({ metric: s })),
 373→        pressMentions: trustPress.split('\n').filter(Boolean).map(p => {
 374→          const parts = p.split('|').map(s => s.trim());
 375→          return { outlet: parts[0] || p, quote: parts[1] || undefined };
 376→        }),
 377→        reviews: [{ platform: trustReviewPlatform as any, rating: parseFloat(trustReviewRating) || 4.5, count: parseInt(trustReviewCount) || 100 }],
 378→      };
 379→      const result = await generateTrustSignals(config, trustOrgName);
 380→      setTrustResult(result);
 381→    } catch (e) { console.error(e); }
 382→    finally { setIsLoading(false); }
 383→  };
 384→
 385→  const handleGenerateCredentials = async () => {
 386→    if (!credName || !credTitle) return;
 387→    if (!onDeductCredits(EEAT_CREDITS.credentials)) return;
 388→    setIsLoading(true); setCredResult(null);
 389→    try {
 390→      const profile = buildAuthorProfile(credName, credTitle, credOrg, credYears, credSpecs, '', '', credEducation, credCredentials, credAwards);
 391→      const result = await generateCredentials(profile);
 392→      setCredResult(result);
 393→    } catch (e) { console.error(e); }
 394→    finally { setIsLoading(false); }
 395→  };
 396→
 397→  const handleGenerateCitation = async () => {
 398→    if (!citeName || !citeTitle) return;
 399→    if (!onDeductCredits(EEAT_CREDITS.citationBlock)) return;
 400→    setIsLoading(true); setCiteResult(null);
 401→    try {
 402→      const profile = buildAuthorProfile(citeName, citeTitle, citeOrg, citeYears, citeSpecs, citeLinkedin, citePhotoUrl, [], []);
 403→      const result = await generateCitationBlock(profile, citeArticleTitle || undefined);
 404→      setCiteResult(result);
 405→    } catch (e) { console.error(e); }
 406→    finally { setIsLoading(false); }
 407→  };
 408→
 409→  const handleAudit = async () => {
 410→    if (!auditUrl) return;
 411→    if (!onDeductCredits(EEAT_CREDITS.audit)) return;
 412→
 413→    // Check pre-generated cache — match hostname
 414→    const cachedEeat = appHistory && appHistory.length > 0 ? appHistory[0]?.preGenerated?.eeatAudit : undefined;
 415→    if (cachedEeat?.scores) {
 416→      let cachedHostname = '';
 417→      let inputHostname = '';
 418→      try { cachedHostname = new URL(cachedEeat.url).hostname; } catch { cachedHostname = cachedEeat.url; }
 419→      try { inputHostname = new URL(auditUrl.startsWith('http') ? auditUrl : `https://${auditUrl}`).hostname; } catch { inputHostname = auditUrl; }
 420→
 421→      if (cachedHostname === inputHostname) {
 422→        const result = cachedEeat as EeatAuditResult;
 423→        setAuditResult(result);
 424→        saveAuditToHistory(result, auditBrand || undefined);
 425→        setAuditHistory(getAuditHistory());
 426→        return;
 427→      }
 428→    }
 429→
 430→    setIsLoading(true); setAuditResult(null);
 431→    try {
 432→      const result = await auditEeat(auditUrl, auditBrand || undefined);
 433→      setAuditResult(result);
 434→      // Feature 9: Save to history
 435→      saveAuditToHistory(result, auditBrand || undefined);
 436→      setAuditHistory(getAuditHistory());
 437→    } catch (e) { console.error(e); }
 438→    finally { setIsLoading(false); }
 439→  };
 440→
 441→  // ── Feature 8: Workflow helpers ──
 442→  const getAuditIssues = useCallback(() => {
 443→    if (!auditResult) return [];
 444→    return auditResult.findings.filter(f => f.status === 'missing' || f.status === 'incomplete');
 445→  }, [auditResult]);
 446→
 447→  const handleCorrectFinding = (category: string) => {
 448→    const tab = CATEGORY_TO_TAB[category];
 449→    if (tab) setActiveTab(tab);
 450→  };
 451→
 452→  const handleCorrectAll = () => {
 453→    const issues = getAuditIssues();
 454→    if (issues.length > 0) {
 455→      const firstCategory = issues[0].category;
 456→      handleCorrectFinding(firstCategory);
 457→    }
 458→  };
 459→
 460→  const estimateGasCost = useCallback(() => {
 461→    const issues = getAuditIssues();
